"use client";

import { type Vulnerability } from "../../lib/api";
import { SEVERITY_CONFIG } from "../styles";

interface PRCardProps {
  vuln: Vulnerability;
  index: number;
}

function PRCard({ vuln, index }: PRCardProps) {
  const cfg = SEVERITY_CONFIG[vuln.severity] ?? SEVERITY_CONFIG.LOW;

  return (
    <div className="pr-card" style={{ animationDelay: `${index * 80}ms` }}>
      <div
        style={{
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "space-between",
          marginBottom: "0.75rem",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
          <div
            style={{
              width: 36,
              height: 36,
              borderRadius: "0.5rem",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              background: "rgba(99,102,241,0.15)",
              border: "1px solid rgba(99,102,241,0.2)",
            }}
          >
            <span
              className="material-symbols-outlined"
              style={{ color: "#818cf8", fontSize: 18 }}
            >
              alt_route
            </span>
          </div>
          <div>
            <p
              style={{
                fontSize: "0.875rem",
                fontWeight: 600,
                color: "#fff",
                lineHeight: 1.2,
                marginBottom: 2,
              }}
            >
              Fix {vuln.type.replace(/_/g, " ")}
            </p>
            <code
              style={{
                fontSize: "0.75rem",
                color: "#6b7280",
                fontFamily: "JetBrains Mono, monospace",
              }}
            >
              {vuln.file}:{vuln.line}
            </code>
          </div>
        </div>
        <span
          style={{
            fontSize: "0.7rem",
            padding: "2px 8px",
            borderRadius: 9999,
            fontWeight: 600,
            color: cfg.color,
            background: cfg.bg,
            whiteSpace: "nowrap",
          }}
        >
          Pending
        </span>
      </div>

      <p
        style={{
          fontSize: "0.75rem",
          color: "#6b7280",
          lineHeight: 1.6,
          marginBottom: "1rem",
        }}
      >
        {vuln.fix_suggestion}
      </p>

      <button
        style={{
          width: "100%",
          padding: "0.5rem",
          borderRadius: "0.5rem",
          fontSize: "0.75rem",
          fontWeight: 600,
          color: "#818cf8",
          border: "1px solid rgba(99,102,241,0.2)",
          background: "transparent",
          cursor: "pointer",
          transition: "background 0.2s",
          fontFamily: "Syne, sans-serif",
        }}
        onMouseEnter={(e) =>
          (e.currentTarget.style.background = "rgba(99,102,241,0.1)")
        }
        onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
      >
        View PR →
      </button>
    </div>
  );
}

interface PRCardsProps {
  vulnerabilities: Vulnerability[];
}

export default function PRCards({ vulnerabilities }: PRCardsProps) {
  const visible = vulnerabilities.slice(0, 6);

  return (
    <>
      <style>{`
        .pr-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
          gap: 1rem;
          padding: 1.5rem;
        }
        .pr-card {
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 14px;
          padding: 1.25rem;
          transition: border-color 0.3s, transform 0.2s;
          animation: rowIn 0.4s ease both;
        }
        .pr-card:hover {
          border-color: rgba(99,102,241,0.3);
          transform: translateY(-2px);
        }
      `}</style>

      <div className="card">
        <div className="card-header">
          <span className="card-title">Auto-Generated PRs</span>
          <button
            style={{
              fontSize: "0.75rem",
              color: "#6366f1",
              fontWeight: 700,
              background: "none",
              border: "none",
              cursor: "pointer",
              fontFamily: "Syne, sans-serif",
            }}
          >
            View all →
          </button>
        </div>
        <div className="pr-grid">
          {visible.map((v, i) => (
            <PRCard key={`${v.file}-${v.line}-${i}`} vuln={v} index={i} />
          ))}
        </div>
      </div>
    </>
  );
}
