"use client";

import { type AuditData, type MetricsData } from "../../lib/api";

interface MetricsRowProps {
  auditData: AuditData;
  metrics: MetricsData | null;
  beforeScore: number;
}

function MetricCard({
  label,
  value,
  icon,
  accent,
}: {
  label: string;
  value: string;
  icon: string;
  accent: string;
}) {
  return (
    <>
      <style>{`
        .metric-card {
          position: relative;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 16px;
          padding: 1.25rem 1.5rem;
          display: flex;
          align-items: center;
          gap: 1rem;
          overflow: hidden;
          transition: border-color 0.3s, transform 0.2s;
        }
        .metric-card:hover { transform: translateY(-2px); }
        .metric-glow {
          position: absolute;
          top: -20px; left: -20px;
          width: 80px; height: 80px;
          background: radial-gradient(circle, var(--accent, #6366f1) 0%, transparent 70%);
          opacity: 0.12;
          pointer-events: none;
        }
        .metric-icon { font-size: 1.5rem; color: var(--accent, #6366f1); flex-shrink: 0; }
        .metric-value {
          font-size: 1.5rem; font-weight: 800; color: #fff;
          letter-spacing: -0.03em; line-height: 1; margin-bottom: 2px;
        }
        .metric-label {
          font-size: 0.7rem; font-weight: 600; color: #6b7280;
          text-transform: uppercase; letter-spacing: 0.08em;
        }
        .metrics-row {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 1rem;
        }
      `}</style>
      <div
        className="metric-card"
        style={{ "--accent": accent } as React.CSSProperties}
      >
        <div className="metric-glow" />
        <span className="metric-icon material-symbols-outlined">{icon}</span>
        <div>
          <p className="metric-value">{value}</p>
          <p className="metric-label">{label}</p>
        </div>
      </div>
    </>
  );
}

import React from "react";

export default function MetricsRow({
  auditData,
  metrics,
  beforeScore,
}: MetricsRowProps) {
  const afterScore = auditData.overallScore ?? 92;

  return (
    <div className="metrics-row">
      <MetricCard
        label="Score Before"
        value={`${Math.max(10, beforeScore)}%`}
        icon="trending_down"
        accent="#ef4444"
      />
      <MetricCard
        label="Score After"
        value={`${afterScore}%`}
        icon="trending_up"
        accent="#10b981"
      />
      <MetricCard
        label="Time Saved"
        value={`${auditData.impact.time_saved_hours}h`}
        icon="schedule"
        accent="#6366f1"
      />
      <MetricCard
        label="Cost Saved"
        value={auditData.impact.savings}
        icon="payments"
        accent="#8b5cf6"
      />
      {metrics && (
        <MetricCard
          label="Efficiency"
          value={metrics.efficiency_improvement}
          icon="bolt"
          accent="#f59e0b"
        />
      )}
    </div>
  );
}
