"use client";

import { useState, useEffect, useCallback } from "react";
import {
  getDemoAudit,
  runAudit,
  getMetrics,
  type AuditData,
  type MetricsData,
} from "../lib/api";
import { GLOBAL_STYLES } from "./styles";

import Navbar, { type ApiStatus } from "./Navbar/Navbar";
import Hero, { type ScanMode } from "./Hero/Hero";
import ErrorBanner from "./ErrorBanner/ErrorBanner";
import MetricsRow from "./MetricsRow/MetricsRow";
import ScoreComparison from "./ScoreComparison/ScoreComparison";
import SeverityBreakdown from "./SeverityBreakdown/SeverityBreakdown";
import VulnerabilitiesTable from "./VulnerabilitiesTable/VulnerabilitiesTable";
import PRCards from "./PRCards/PRCards";
import EmptyState from "./EmptyState/EmptyState";

export default function DashboardUI() {
  const [loading, setLoading] = useState(false);
  const [auditData, setAuditData] = useState<AuditData | null>(null);
  const [metrics, setMetrics] = useState<MetricsData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [scanMode, setScanMode] = useState<ScanMode>("demo");
  const [lastAudit, setLastAudit] = useState<string | null>(null);
  const [apiStatus, setApiStatus] = useState<ApiStatus>("checking");

  // ── Check API health on mount ────────────────────────────────────────────────
  useEffect(() => {
    const check = async () => {
      try {
        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_URL || "http://localhost:3000"}/health`,
        );
        setApiStatus(res.ok ? "online" : "offline");
      } catch {
        setApiStatus("offline");
      }
    };
    check();
  }, []);

  // ── Run audit handler ────────────────────────────────────────────────────────
  const handleRunAudit = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result =
        scanMode === "demo" || apiStatus === "offline"
          ? await getDemoAudit()
          : await runAudit([
              {
                file: "routes/user.js",
                content: `const express = require('express');\nconst db = require('./db');\nrouter.get('/user/:id', (req, res) => {\n  const userId = req.params.id;\n  db.query(\`SELECT * FROM users WHERE id = '\${userId}'\`, (err, rows) => { res.json(rows); });\n});`,
              },
            ]);

      if (result.success) {
        setAuditData(result.data);
        setLastAudit(new Date().toLocaleTimeString());
        try {
          const m = await getMetrics();
          if (m.success) setMetrics(m.data);
        } catch {}
      } else {
        setError("Audit failed. Please try again.");
      }
    } catch {
      setError(
        "Cannot reach the API server. Switch to Demo mode or check your connection.",
      );
    } finally {
      setLoading(false);
    }
  }, [scanMode, apiStatus]);

  // ── Derived values ───────────────────────────────────────────────────────────
  const beforeScore = 100 - (auditData?.summary.total ?? 0) * 8;
  const afterScore = auditData?.overallScore ?? 92;

  return (
    <>
      <style>{GLOBAL_STYLES}</style>

      <div className="dashboard-root">
        <div className="content">
          {/* 1. Navigation bar */}
          <Navbar apiStatus={apiStatus} />

          {/* 2. Hero + Run Audit button */}
          <Hero
            loading={loading}
            hasData={!!auditData}
            scanMode={scanMode}
            lastAudit={lastAudit}
            onRunAudit={handleRunAudit}
            onScanModeChange={setScanMode}
          />

          <div className="main-grid">
            {/* 3. Error banner (conditional) */}
            {error && <ErrorBanner message={error} />}

            {auditData ? (
              <>
                {/* 4. Metric cards row */}
                <MetricsRow
                  auditData={auditData}
                  metrics={metrics}
                  beforeScore={beforeScore}
                />

                {/* 5. Score rings + Severity breakdown (side by side) */}
                <div className="split-row">
                  <ScoreComparison
                    beforeScore={beforeScore}
                    afterScore={afterScore}
                  />
                  <SeverityBreakdown
                    summary={auditData.summary}
                    impact={auditData.impact}
                  />
                </div>

                {/* 6. Vulnerabilities table */}
                <VulnerabilitiesTable
                  vulnerabilities={auditData.vulnerabilities}
                  total={auditData.summary.total}
                />

                {/* 7. Auto-generated PR cards */}
                {auditData.vulnerabilities.length > 0 && (
                  <PRCards vulnerabilities={auditData.vulnerabilities} />
                )}
              </>
            ) : (
              /* 8. Empty state (before first audit) */
              !loading && <EmptyState />
            )}
          </div>
        </div>
      </div>
    </>
  );
}
